+        proptest! {
+            #[test]
+            fn is_known_short_flag_accepts_known_char_combos(
+                combo in prop::sample::select(vec![
+                    "-v", "-c", "-r", "-p", "-e",
+                    "-vc", "-vp", "-cr", "-vcr", "-vcrpe",
+                ]),
