+            ) {
+                let token = format!("--{body}");
+                assert!(
+                    !is_known_short_flag(&token),
+                    "'--{body}' should not be a short flag"
+                );
+            }
+
+            #[test]
+            fn is_negative_numeric_token_accepts_negative_integers(
