+            #[test]
+            fn preprocess_empty_returns_pi_program_name(_dummy in Just(())) {
+                let result = preprocess_extension_flags(&[]);
+                assert_eq!(result.0, vec!["pi"]);
+                let extracted: &[ExtensionCliFlag] = &result.1;
+                assert!(extracted.is_empty());
